namespace sv_47cf1f0b4a6f4eda9615493f48e63c40.Services;

public enum Severity { Info, Warning, Critical }

public class NotificationItem
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; }
}

/// <summary>
/// Scoped service (per-circuit on Server = per-user) that holds notification state
/// and raises OnChange so any subscribing component re-renders.
/// </summary>
public class NotificationState
{
    private readonly List<NotificationItem> _items = [];
    private int _nextId = 1;

    public IReadOnlyList<NotificationItem> Items => _items;
    public int UnreadCount => _items.Count(n => !n.IsRead);

    public event Action? OnChange;

    public void Add(string title, Severity severity)
    {
        _items.Insert(0, new NotificationItem
        {
            Id = _nextId++,
            Title = title,
            Severity = severity,
            Timestamp = DateTime.Now
        });
        NotifyChanged();
    }

    public void MarkRead(int id)
    {
        var item = _items.FirstOrDefault(n => n.Id == id);
        if (item is not null)
        {
            item.IsRead = true;
            NotifyChanged();
        }
    }

    public void Dismiss(int id)
    {
        _items.RemoveAll(n => n.Id == id);
        NotifyChanged();
    }

    public void MarkAllRead()
    {
        foreach (var item in _items)
            item.IsRead = true;
        NotifyChanged();
    }

    private void NotifyChanged() => OnChange?.Invoke();
}

@using sv_47cf1f0b4a6f4eda9615493f48e63c40.Services
@inject NotificationState State
@implements IDisposable
@rendermode InteractiveServer

<a href="notifications" class="nav-link notification-bell">
    <span class="bi bi-bell-nav-menu" aria-hidden="true"></span>
    Notifications
    @if (State.UnreadCount > 0)
    {
        <span class="badge bg-danger ms-1">@State.UnreadCount</span>
    }
</a>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        State.OnChange += _handler;
    }

    public void Dispose()
    {
        State.OnChange -= _handler;
    }
}

@page "/notifications"
@using sv_47cf1f0b4a6f4eda9615493f48e63c40.Services
@inject NotificationState State
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<button class="btn btn-secondary mb-3" @onclick="State.MarkAllRead">Mark All Read</button>

@if (State.Items.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Severity</th>
                <th>Status</th>
                <th>Timestamp</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in State.Items)
            {
                <tr class="@(item.IsRead ? "" : "table-active")">
                    <td>@item.Id</td>
                    <td>@item.Title</td>
                    <td>@item.Severity</td>
                    <td>@(item.IsRead ? "Read" : "Unread")</td>
                    <td>@item.Timestamp.ToString("g")</td>
                    <td>
                        @if (!item.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => State.MarkRead(item.Id)">
                                Mark Read
                            </button>
                        }
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => State.Dismiss(item.Id)">
                            Dismiss
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        State.OnChange += _handler;
    }

    public void Dispose()
    {
        State.OnChange -= _handler;
    }
}

@page "/dashboard"
@using sv_47cf1f0b4a6f4eda9615493f48e63c40.Services
@inject NotificationState State
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard</PageTitle>

<h1>Dashboard</h1>

<h3>Recent Unread Notifications</h3>

@if (!_recentUnread.Any())
{
    <p><em>No unread notifications.</em></p>
}
else
{
    <ul class="list-group mb-4">
        @foreach (var item in _recentUnread)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                <span>
                    <strong>@item.Title</strong>
                    <small class="text-muted ms-2">@item.Severity — @item.Timestamp.ToString("t")</small>
                </span>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => State.Dismiss(item.Id)">
                    Dismiss
                </button>
            </li>
        }
    </ul>
}

<p class="text-muted"><em>A simulated notification arrives every 15 seconds while you're on this page.</em></p>

@code {
    private IEnumerable<NotificationItem> _recentUnread =>
        State.Items.Where(n => !n.IsRead).Take(3);

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _handler;

    private static readonly string[] SampleTitles =
    [
        "CPU usage spike detected",
        "New deployment completed",
        "Disk space running low",
        "Security scan finished",
        "Backup succeeded",
        "Service latency increased"
    ];

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        State.OnChange += _handler;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));
        _ = SimulateIncomingNotifications(_cts.Token);
    }

    private async Task SimulateIncomingNotifications(CancellationToken ct)
    {
        while (await _timer!.WaitForNextTickAsync(ct))
        {
            var title = SampleTitles[Random.Shared.Next(SampleTitles.Length)];
            var severity = (Severity)Random.Shared.Next(0, 3);
            State.Add(title, severity);
        }
    }

    public async ValueTask DisposeAsync()
    {
        State.OnChange -= _handler;
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

